/**
 * CASHFLOW-CURSOR-112 — Two-user household privacy browser smoke.
 *
 * Requires isolated owner + member test accounts in the same household.
 * Env: CASHFLOW_OWNER_EMAIL, CASHFLOW_OWNER_PASSWORD,
 *      CASHFLOW_MEMBER_EMAIL, CASHFLOW_MEMBER_PASSWORD
 * Optional: CASHFLOW_E2E_BASE_URL (default http://127.0.0.1:5212)
 *
 * If the four credential variables are missing, loads `.tmp/c112-two-user-smoke.env`
 * when present (generated by scripts/seed-two-user-privacy-test-users.mjs).
 */
import { chromium } from "playwright";
import {
  loadSmokeEnvFile,
  parseEnvFile,
  SMOKE_ENV_FILE,
} from "./lib/two-user-privacy-test-support.mjs";

function loadCredentials() {
  const missing = [
    "CASHFLOW_OWNER_EMAIL",
    "CASHFLOW_OWNER_PASSWORD",
    "CASHFLOW_MEMBER_EMAIL",
    "CASHFLOW_MEMBER_PASSWORD",
  ].filter((key) => !process.env[key]?.trim());

  if (missing.length > 0) {
    loadSmokeEnvFile();
  }
}

loadCredentials();

const BASE_URL = process.env.CASHFLOW_E2E_BASE_URL ?? "http://127.0.0.1:5212";

const OWNER_EMAIL = process.env.CASHFLOW_OWNER_EMAIL?.trim();
const OWNER_PASSWORD = process.env.CASHFLOW_OWNER_PASSWORD;
const MEMBER_EMAIL = process.env.CASHFLOW_MEMBER_EMAIL?.trim();
const MEMBER_PASSWORD = process.env.CASHFLOW_MEMBER_PASSWORD;

const REQUIRED_ENV = [
  ["CASHFLOW_OWNER_EMAIL", OWNER_EMAIL],
  ["CASHFLOW_OWNER_PASSWORD", OWNER_PASSWORD],
  ["CASHFLOW_MEMBER_EMAIL", MEMBER_EMAIL],
  ["CASHFLOW_MEMBER_PASSWORD", MEMBER_PASSWORD],
];

const SHARED_PAGES = [
  { path: "/", marker: "Household Cashflow Dashboard", label: "Dashboard" },
  { path: "/bills", marker: "All Bills", label: "Bills" },
  { path: "/expenses", marker: "Expenses", label: "Expenses" },
  { path: "/debt", marker: "Debt Tracker", label: "Debt" },
  { path: "/settings", marker: "Settings", label: "Settings" },
];

const COPY = {
  ownerInviteReadOnly: "Only a household owner can invite members.",
  ownerManageReadOnly: "Only a household owner can manage members.",
  cashflowStartReadOnly: "Only a household admin can change the cashflow start date.",
  importRollbackReadOnly: "Only a household owner can roll back spreadsheet imports.",
  privateCash: "Your private balance snapshot. Only you can see this amount.",
  paycheckPrivacy:
    "Other household members cannot see your paycheck amount.",
  personMappingTitle: "Your budget profile",
  personMappingPrivacy:
    "Your private cash, savings, receipts, paycheck, and audit history remain private.",
  receiptPrivate: "Receipt belongs only to you until approval.",
  receiptCandidatePrivate: "Only you can see this candidate until you approve it.",
  savingsSharedPrivacy: "Only your target and contribution details are shown.",
  savingsOtherPrivacy: "The other user's target and saved amount remain private.",
  savingsSectionIntro:
    "Other members' private contribution details stay hidden.",
};

const UUID_PATTERN =
  /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/i;

function assert(condition, message) {
  if (!condition) {
    throw new Error(message);
  }
}

function isAllowedConsoleError(text) {
  const normalized = text.trim();
  if (!normalized) {
    return true;
  }
  if (normalized.includes("favicon.ico")) {
    return true;
  }
  if (normalized.includes("Download the React DevTools")) {
    return true;
  }
  return false;
}

function trackPageDiagnostics(page, bucket, label) {
  page.on("console", (msg) => {
    if (msg.type() === "error" && !isAllowedConsoleError(msg.text())) {
      bucket.push(`[${label} console] ${msg.text()}`);
    }
  });
  page.on("pageerror", (error) => {
    bucket.push(`[${label} pageerror] ${error.message}`);
  });
}

async function login(page, email, password, label) {
  await page.goto(`${BASE_URL}/login`, { waitUntil: "domcontentloaded" });
  await page.locator("#email").fill(email);
  await page.locator("#password").fill(password);
  await page.locator('button[type="submit"]').click();
  await page.waitForURL((url) => !url.pathname.includes("/login"), {
    timeout: 25000,
  });
  assert(!(await page.url()).includes("/login"), `${label} login failed`);
}

async function visit(page, path) {
  await page.goto(`${BASE_URL}${path}`, { waitUntil: "domcontentloaded" });
  await page.waitForTimeout(1200);
}

async function assertSharedPages(page, label) {
  for (const route of SHARED_PAGES) {
    await visit(page, route.path);
    await page.getByText(route.marker, { exact: false }).first().waitFor({
      timeout: 15000,
    });
    assert(
      !(await page.url()).includes("/login"),
      `${label} was redirected away from ${route.label}`
    );
  }
}

async function countVisibleButtons(page, name) {
  return page.getByRole("button", { name, exact: true }).count();
}

async function collectSettingsPrivacySnapshot(page) {
  await visit(page, "/settings");
  await page.getByRole("heading", { name: "Settings" }).waitFor({ timeout: 15000 });

  const bodyText = await page.locator("body").innerText();
  const latestAmountMatch = bodyText.match(/Latest amount:\s*[^\n]+/);
  const paycheckAmount = await page.locator("#paycheck-amount").inputValue().catch(() => "");
  const privateGoalNames = await page.evaluate(() => {
    const names = [];
    for (const section of document.querySelectorAll(".rounded-lg.border.p-4")) {
      const text = section.textContent ?? "";
      if (text.includes("Type: Private")) {
        const heading = section.querySelector("h3");
        if (heading?.textContent) {
          names.push(heading.textContent.trim());
        }
      }
    }
    return names;
  });
  const receiptFileNames = await page.evaluate(() => {
    const card = [...document.querySelectorAll("[data-slot='card']")].find((node) =>
      (node.textContent ?? "").includes("Receipt upload storage")
    );
    if (!card) {
      return [];
    }
    return [...card.querySelectorAll("tbody tr")].map((row) => {
      const firstCell = row.querySelector("td");
      return firstCell?.textContent?.trim() ?? "";
    }).filter(Boolean);
  });
  const cashDeductionRows = await page.evaluate(() => {
    const card = [...document.querySelectorAll("[data-slot='card']")].find((node) =>
      (node.textContent ?? "").includes("Cash payment deductions")
    );
    if (!card) {
      return [];
    }
    return [...card.querySelectorAll("tbody tr")].map((row) => row.textContent?.trim() ?? "").filter(Boolean);
  });
  const profileLabel = await page.locator("#budget-profile").innerText().catch(() => "");

  return {
    bodyText,
    latestAmountLine: latestAmountMatch?.[0] ?? null,
    paycheckAmount: paycheckAmount.trim(),
    privateGoalNames,
    receiptFileNames,
    cashDeductionRows,
    profileLabel: profileLabel.trim(),
    sendInviteCount: await countVisibleButtons(page, "Send invite"),
    removeMemberCount: await countVisibleButtons(page, "Remove member"),
    cancelInviteCount: await countVisibleButtons(page, "Cancel invite"),
    resendInviteCount: await countVisibleButtons(page, "Resend invite"),
    cashflowSaveCount: await page
      .getByRole("button", { name: /Save start date|Change start date/ })
      .count(),
    rollbackCount: await countVisibleButtons(page, "Roll back import"),
    applyImportCount: await countVisibleButtons(page, "Apply import"),
  };
}

function assertOwnerOnlyControls(snapshot) {
  assert(
    snapshot.sendInviteCount > 0,
    "Owner should see Send invite action"
  );
  assert(
    !snapshot.bodyText.includes(COPY.ownerInviteReadOnly),
    "Owner should not see invite read-only copy"
  );
  assert(
    !snapshot.bodyText.includes(COPY.ownerManageReadOnly),
    "Owner should not see member-management read-only copy"
  );
  assert(
    !snapshot.bodyText.includes(COPY.cashflowStartReadOnly),
    "Owner should not see cashflow start read-only copy"
  );
}

function assertMemberReadOnlyControls(snapshot) {
  assert(snapshot.sendInviteCount === 0, "Member must not see Send invite");
  assert(snapshot.removeMemberCount === 0, "Member must not see Remove member");
  assert(snapshot.cancelInviteCount === 0, "Member must not see Cancel invite");
  assert(snapshot.resendInviteCount === 0, "Member must not see Resend invite");
  assert(snapshot.cashflowSaveCount === 0, "Member must not see cashflow start save");
  assert(snapshot.applyImportCount === 0, "Member must not see Apply import");
  assert(snapshot.rollbackCount === 0, "Member must not see Roll back import");
  assert(
    snapshot.bodyText.includes(COPY.ownerInviteReadOnly),
    "Member should see invite read-only copy"
  );
  assert(
    snapshot.bodyText.includes(COPY.ownerManageReadOnly),
    "Member should see member-management read-only copy"
  );
  assert(
    snapshot.bodyText.includes(COPY.cashflowStartReadOnly),
    "Member should see cashflow start read-only copy"
  );
  assert(
    snapshot.bodyText.includes(COPY.importRollbackReadOnly),
    "Member should see import rollback read-only copy"
  );
}

function assertPrivateSectionsLoad(snapshot, label) {
  assert(
    snapshot.bodyText.includes(COPY.privateCash),
    `${label} should see private current cash copy`
  );
  assert(
    snapshot.bodyText.includes(COPY.paycheckPrivacy),
    `${label} should see paycheck privacy copy`
  );
  assert(
    snapshot.bodyText.includes(COPY.personMappingTitle),
    `${label} should see person mapping section`
  );
  assert(
    snapshot.bodyText.includes(COPY.personMappingPrivacy),
    `${label} should see person mapping privacy copy`
  );
  assert(
    snapshot.bodyText.includes("Receipt upload storage"),
    `${label} should see receipt upload section`
  );
  assert(
    snapshot.bodyText.includes(COPY.savingsSectionIntro),
    `${label} should see savings privacy intro`
  );
}

function assertSharedGoalPrivacyCopy(snapshot, label) {
  if (!snapshot.bodyText.includes("Type: Shared")) {
    return;
  }
  assert(
    snapshot.bodyText.includes(COPY.savingsSharedPrivacy) ||
      snapshot.bodyText.includes(COPY.savingsOtherPrivacy),
    `${label} should show shared-goal privacy copy when shared goals exist`
  );
}

function assertNoCrossUserLeak(ownerSnapshot, memberSnapshot) {
  for (const goalName of ownerSnapshot.privateGoalNames) {
    assert(
      !memberSnapshot.bodyText.includes(goalName),
      `Member page leaked owner's private goal "${goalName}"`
    );
  }
  for (const goalName of memberSnapshot.privateGoalNames) {
    assert(
      !ownerSnapshot.bodyText.includes(goalName),
      `Owner page leaked member's private goal "${goalName}"`
    );
  }

  if (
    ownerSnapshot.latestAmountLine &&
    ownerSnapshot.latestAmountLine !== "Latest amount: —" &&
    !ownerSnapshot.latestAmountLine.includes("No current amount")
  ) {
    assert(
      !memberSnapshot.bodyText.includes(ownerSnapshot.latestAmountLine),
      "Member page leaked owner's private current cash line"
    );
  }
  if (
    memberSnapshot.latestAmountLine &&
    memberSnapshot.latestAmountLine !== "Latest amount: —" &&
    !memberSnapshot.latestAmountLine.includes("No current amount")
  ) {
    assert(
      !ownerSnapshot.bodyText.includes(memberSnapshot.latestAmountLine),
      "Owner page leaked member's private current cash line"
    );
  }

  for (const [sourceLabel, sourceAmount, otherSnapshot, leakMessage] of [
    ["owner", ownerSnapshot.paycheckAmount, memberSnapshot, "Member page leaked owner's paycheck amount"],
    ["member", memberSnapshot.paycheckAmount, ownerSnapshot, "Owner page leaked member's paycheck amount"],
  ]) {
    const normalized = String(sourceAmount ?? "").trim();
    if (!normalized || normalized === "0" || normalized === "0.00") {
      continue;
    }

    assert(
      !otherSnapshot.bodyText.includes(normalized),
      `${leakMessage} (raw value ${sourceLabel})`
    );

    const formatted = Number(normalized);
    if (Number.isFinite(formatted) && formatted > 0) {
      const plainCurrency = `$${formatted.toFixed(2)}`;
      const groupedCurrency = new Intl.NumberFormat(undefined, {
        style: "currency",
        currency: "USD",
      }).format(formatted);
      assert(
        !otherSnapshot.bodyText.includes(plainCurrency) &&
          !otherSnapshot.bodyText.includes(groupedCurrency),
        leakMessage
      );
    }
  }

  for (const fileName of ownerSnapshot.receiptFileNames) {
    assert(
      !memberSnapshot.bodyText.includes(fileName),
      `Member page leaked owner receipt upload "${fileName}"`
    );
  }
  for (const fileName of memberSnapshot.receiptFileNames) {
    assert(
      !ownerSnapshot.bodyText.includes(fileName),
      `Owner page leaked member receipt upload "${fileName}"`
    );
  }

  for (const row of ownerSnapshot.cashDeductionRows) {
    if (row.length > 12) {
      assert(
        !memberSnapshot.bodyText.includes(row),
        "Member page leaked owner cash payment deduction row"
      );
    }
  }
  for (const row of memberSnapshot.cashDeductionRows) {
    if (row.length > 12) {
      assert(
        !ownerSnapshot.bodyText.includes(row),
        "Owner page leaked member cash payment deduction row"
      );
    }
  }
}

function assertNoSecretsInUi(ownerSnapshot, memberSnapshot) {
  for (const [label, snapshot] of [
    ["owner", ownerSnapshot],
    ["member", memberSnapshot],
  ]) {
    assert(
      !snapshot.bodyText.toLowerCase().includes("service_role"),
      `${label} UI exposed service_role text`
    );
    assert(
      !snapshot.bodyText.includes("/object/public/receipt"),
      `${label} UI exposed public receipt storage URL`
    );
    assert(
      !UUID_PATTERN.test(snapshot.bodyText),
      `${label} UI exposed a raw UUID in visible copy`
    );
  }
}

function assertDistinctSessions(ownerSnapshot, memberSnapshot) {
  if (ownerSnapshot.profileLabel && memberSnapshot.profileLabel) {
    assert(
      ownerSnapshot.profileLabel !== memberSnapshot.profileLabel,
      "Owner and member appear to share the same budget profile label in Settings"
    );
  }
}

async function main() {
  const missing = REQUIRED_ENV.filter(([, value]) => !value).map(([name]) => name);
  if (missing.length > 0) {
    console.error(
      "Two-user privacy smoke requires owner and member credentials via environment variables."
    );
    console.error(`Missing: ${missing.join(", ")}`);
    console.error(
      "Set CASHFLOW_OWNER_EMAIL, CASHFLOW_OWNER_PASSWORD, CASHFLOW_MEMBER_EMAIL, and CASHFLOW_MEMBER_PASSWORD,"
    );
    console.error(
      "or run `node scripts/seed-two-user-privacy-test-users.mjs` to create `.tmp/c112-two-user-smoke.env`, then rerun."
    );
    if (!parseEnvFile(SMOKE_ENV_FILE).CASHFLOW_OWNER_EMAIL) {
      console.error(`Smoke env file not found or incomplete: ${SMOKE_ENV_FILE}`);
    }
    process.exit(2);
  }

  if (OWNER_EMAIL === MEMBER_EMAIL) {
    console.error("Owner and member emails must be different test accounts.");
    process.exit(2);
  }

  const ownerConsoleErrors = [];
  const memberConsoleErrors = [];
  const browser = await chromium.launch({ headless: true });

  try {
    const ownerContext = await browser.newContext();
    const memberContext = await browser.newContext();
    const ownerPage = await ownerContext.newPage();
    const memberPage = await memberContext.newPage();

    trackPageDiagnostics(ownerPage, ownerConsoleErrors, "owner");
    trackPageDiagnostics(memberPage, memberConsoleErrors, "member");

    console.log(`Running two-user privacy smoke against ${BASE_URL}`);

    await login(ownerPage, OWNER_EMAIL, OWNER_PASSWORD, "Owner");
    await login(memberPage, MEMBER_EMAIL, MEMBER_PASSWORD, "Member");

    await assertSharedPages(ownerPage, "Owner");
    await assertSharedPages(memberPage, "Member");

    const ownerSnapshot = await collectSettingsPrivacySnapshot(ownerPage);
    const memberSnapshot = await collectSettingsPrivacySnapshot(memberPage);

    assertOwnerOnlyControls(ownerSnapshot);
    assertMemberReadOnlyControls(memberSnapshot);
    assertPrivateSectionsLoad(ownerSnapshot, "Owner");
    assertPrivateSectionsLoad(memberSnapshot, "Member");
    assertSharedGoalPrivacyCopy(ownerSnapshot, "Owner");
    assertSharedGoalPrivacyCopy(memberSnapshot, "Member");
    assertNoCrossUserLeak(ownerSnapshot, memberSnapshot);
    assertNoSecretsInUi(ownerSnapshot, memberSnapshot);
    assertDistinctSessions(ownerSnapshot, memberSnapshot);

    assert(
      ownerConsoleErrors.length === 0,
      `Owner console/page errors:\n${ownerConsoleErrors.join("\n")}`
    );
    assert(
      memberConsoleErrors.length === 0,
      `Member console/page errors:\n${memberConsoleErrors.join("\n")}`
    );

    console.log("Two-user privacy smoke passed.");
    console.log(
      "Verified: shared pages, owner-only controls, member read-only guards, private sections, cross-user isolation."
    );
    if (
      ownerSnapshot.profileLabel &&
      memberSnapshot.profileLabel &&
      ownerSnapshot.profileLabel !== memberSnapshot.profileLabel
    ) {
      console.log("Person mapping: both users have distinct assigned profiles.");
    } else {
      console.log(
        "Person mapping: sections loaded; reserved-profile conflict path covered by C111 unit tests."
      );
    }

    await ownerContext.close();
    await memberContext.close();
  } finally {
    await browser.close();
  }
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});
